 打开IDEA单击 “File”，选择 “New Project”，切换到 “Spring Initializr” 选项卡下，根据安装的JDK选择对应的版本。单击 “Next” 开始下一步，选择项目所需的依赖，点击 “Finish” 完成。 转到pom.xml添加json的支持。  &lt;dependency&gt; &lt;groupId&gt;com.alibaba&lt;/groupId&gt; &lt;artifactId&gt;fastjson&lt;/artifactId&gt; &lt;version&gt;1.2.47&lt;/version&gt; &lt;/dependency&gt; 创建数据库，修改 resources\application.properties，配置数据源和MyBatis。  #创建数据库名为person，添加student表，包含id,name和sex属性CREATEDATABASE;USE`person`;DROPTABLEIFEXISTS`student`;CREATETABLE`student`(`id`int(16)NOTNULLAUTO_INCREMENTCOMMENT&#39;id&#39;,`name`varchar(32)COLLATEutf8_croatian_ciDEFAULTNULLCOMMENT&#39;姓名&#39;,`sex`tinyint(1)DEFAULT&#39;1&#39;COMMENT&#39;性别&#39;,PRIMARYKEY(`id`))ENGINE=InnoDBDEFAULTCHARSET=utf8COLLATE=utf8_croatian_ci;#数据源spring.datasource.driver-class-name=com.mysql.cj.jdbc.Driverspring.datasource.url=jdbc:mysql://localhost:3306/数据库名?useUnicode=true&amp;characterEncoding=utf-8spring.datasource.username=数据库用户名spring.datasource.password=数据库密码#mybatismybatis.mapperLocations=classpath:mapper/*.xml要将 MyBatis 与 Spring 一起使用，至少需要SqlSessionFactory一个映射器接口。默认情况下，MyBatis-Spring-Boot-Starter 将搜索标有@Mapper注解的映射器。   MyBatis-Spring-Boot-Starter 将：
 自动检测现有 DataSource 将创建并注册一个SqlSessionFactory传递实例DataSource作为输入使用SqlSessionFactoryBean 将创建并注册的一个实例SqlSessionTemplate得到的出SqlSessionFactory 自动扫描您的映射器，将它们链接到SqlSessionTemplate并将它们注册到 Spring 上下文，以便将它们注入到您的 bean 中。   在 resources 下新建mapper命名为 mapper/StudentMapper.xml。在 DemoApplication.java 同级目录下新建映射器 StudentMapper.java，业务处理 StudentService.java，控制层 StudentController.java 以及JavaBean。
StudentMapper.xml &lt;?xml version=&#34;1.0&#34; encoding=&#34;UTF-8&#34; ?&gt; &lt;!DOCTYPE mapper PUBLIC &#34;-//mybatis.org//DTD Mapper 3.0//EN&#34; &#34;http://mybatis.org/dtd/mybatis-3-mapper.dtd&#34;&gt; &lt;!--namespace必须为全类名 --&gt; &lt;mapper namespace=&#34;com.example.demo.StudentMapper&#34;&gt; &lt;select id=&#34;query&#34; resultType=&#34;com.example.demo.Student&#34;&gt; select * from `student` &lt;/select&gt; &lt;insert id=&#34;insert&#34; parameterType=&#34;com.example.demo.Student&#34; useGeneratedKeys=&#34;true&#34; keyProperty=&#34;id&#34;&gt; INSERT INTO `student` (`id`, `name`, `sex`) VALUES(#{id}, #{name}, #{sex}) &lt;/insert&gt; &lt;delete id=&#34;delete&#34; parameterType=&#34;int&#34;&gt; delete from `student` where id=#{id} &lt;/delete&gt; &lt;update id=&#34;update&#34; parameterType=&#34;hashmap&#34;&gt; update `student` set `name`=#{name},`sex`=#{sex} where id=#{id} &lt;/update&gt; &lt;select id=&#34;selectID&#34; parameterType=&#34;int&#34; resultType=&#34;com.example.demo.Student&#34;&gt; select * from `student` where id=#{id} &lt;/select&gt; &lt;select id=&#34;selectName&#34; parameterType=&#34;String&#34; resultType=&#34;com.example.demo.Student&#34;&gt; SELECT * FROM `student` WHERE `name` LIKE #{name} &lt;/select&gt; &lt;/mapper&gt; StudentMapper.java package com.example.demo; import org.apache.ibatis.annotations.Mapper; import java.util.HashMap; import java.util.List; @Mapper public interface StudentMapper { List&lt;Student&gt; query(); int insert(Student s); int delete(int id); int update(HashMap&lt;String,Object&gt; m); List&lt;Student&gt; selectID(int id); List&lt;Student&gt; selectName(String name); } StudentService.java package com.example.demo; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.beans.factory.annotation.Qualifier; import org.springframework.stereotype.Service; import java.util.HashMap; import java.util.List; @Service public class StudentService implements StudentMapper { @Qualifier(&#34;studentMapper&#34;) @Autowired private StudentMapper stuMapper; @Override public List&lt;Student&gt; query() { return stuMapper.query(); } @Override public int insert(Student s) { return stuMapper.insert(s); } @Override public int delete(int id) { return stuMapper.delete(id); } @Override public int update(HashMap&lt;String, Object&gt; m) { return stuMapper.update(m); } @Override public List&lt;Student&gt; selectID(int id) { return stuMapper.selectID(id); } @Override public List&lt;Student&gt; selectName(String name) { return stuMapper.selectName(name); } } StudentController.java package com.example.demo; import com.alibaba.fastjson.JSONArray; import com.alibaba.fastjson.JSONObject; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.beans.factory.annotation.Qualifier; import org.springframework.stereotype.Controller; import org.springframework.web.bind.annotation.GetMapping; import org.springframework.web.bind.annotation.PostMapping; import org.springframework.web.bind.annotation.RequestBody; import org.springframework.web.servlet.View; import java.util.HashMap; import java.util.List; @Controller public class StudentController { @Autowired @Qualifier(&#34;studentService&#34;) private StudentService stuservice; // 全部学生信息 	@GetMapping(value = &#34;/query.do&#34;) public View query() throws Exception { List&lt;Student&gt; data = stuservice.query(); if(data != null) { return new RestData(data); } return new RestData(&#34;暂无数据！&#34;); } // 增加 	@GetMapping(&#34;/insert.do&#34;) public View insert(String name,Integer sex) throws Exception { Student s = new Student(); s.name = name; if(name.length() &lt;0 || name.isEmpty())return new RestData(&#34;&#34;); s.sex = sex; int row = stuservice.insert(s); System.out.println(&#34;done&#34;); return new RestData(&#34;&#34;); } // 根据id删除学生记录 	@GetMapping(value = &#34;/delete.do&#34;) public View delete(Integer id) throws Exception { stuservice.delete(id); return new RestData(&#34;&#34;); } // 修改一条学生信息 	@GetMapping(value = &#34;/update.do&#34;) public View update(@RequestBody HashMap m) throws Exception { int row = stuservice.update(m); return new RestData(&#34;&#34;); } // 根据学号查找一个学生信息 	@GetMapping(value = &#34;/selectID.do&#34;) public View selectID(int id) throws Exception { Student student = stuservice.selectID(id); return new RestData(student); } // 根据姓名查找一个学生信息 	@GetMapping(value = &#34;/selectName.do&#34;) public View selectName(String name) throws Exception { name = &#34;%&#34; + name + &#34;%&#34;; List&lt;Student&gt; row = stuservice.selectName(name); return new RestData(row); } }
